#include <bits/stdc++.h>
using namespace std;
struct Edge{
    int u,v;
}edge[200005];
int n,m,k,a[400005],f[400005],sum;
vector<int> g[400005];
stack<int> ans;
bool des[400005];
int father(int x){
    return f[x]==x ? x:f[x]=father(f[x]);
}
void merge(int x,int y){
    int fx=father(x),fy=father(y);
    if(fx!=fy)
        sum--,f[fy]=fx;
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=0;i<n;i++)
    	f[i]=i;
    for(int i=1;i<=m;i++){
        scanf("%d%d",&edge[i].u,&edge[i].v);
        g[edge[i].u].push_back(edge[i].v);
        g[edge[i].v].push_back(edge[i].u);
    }
    scanf("%d",&k);
    for(int i=1;i<=k;i++){
        scanf("%d",&a[i]);
        des[a[i]]=1;
    }
    sum=n-k;
    for(int i=1;i<=m;i++)
        if(!des[edge[i].u] && !des[edge[i].v])
            merge(edge[i].u,edge[i].v);
    for(int i=k;i;i--){
        ans.push(sum);
        sum++;
        int u=a[i],len=g[u].size();
        for(int j=0;j<len;j++)
        	if(!des[g[u][j]])
        		merge(u,g[u][j]);
		des[u]=0;
    }
    ans.push(sum);
    while(ans.size()){
        printf("%d\n",ans.top());
        ans.pop();
    }
    return 0;
}
